transform_js:
const data = [];
rawData.rows.forEach(r => {
  data.push({ name: r.step, value: r.value });
});
// ファンネルは降順であることが多いのでソートを担保
data.sort((a, b) => b.value - a.value);
transformedData = data;

echarts_js:
option = {
  title: {
    text: 'Sales Pipeline Funnel',
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: '{a} <br/>{b} : {c} ({d}%)'
  },
  series: [
    {
      name: 'Funnel',
      type: 'funnel',
      left: '10%',
      top: 60,
      bottom: 60,
      width: '80%',
      min: 0,
      max: transformedData[0].value,
      minSize: '0%',
      maxSize: '100%',
      sort: 'descending',
      gap: 2,
      label: {
        show: true,
        position: 'inside',
        fontSize: 14,
        color: '#fff'
      },
      labelLine: {
        length: 10,
        lineStyle: {
          width: 1,
          type: 'solid'
        }
      },
      itemStyle: {
        borderColor: '#fff',
        borderWidth: 1
      },
      emphasis: {
        label: {
          fontSize: 20
        }
      },
      data: transformedData
    }
  ]
};
